#include <stdio.h>
#include <stdlib.h>

// Structure for an adjacency list node
typedef struct AdjListNode {
    int vertex;
    struct AdjListNode* next;
} AdjListNode;

// Structure for a graph
typedef struct Graph {
    int numVertices;
    AdjListNode** adjLists;
} Graph;

// Function to create a new adjacency list node
AdjListNode* createNode(int vertex) {
    AdjListNode* newNode = (AdjListNode*) malloc(sizeof(AdjListNode));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->vertex = vertex;
    newNode->next = NULL;
    return newNode;
}

// Function to create a graph with given vertices
Graph* createGraph(int vertices) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    if (!graph) {
        printf("Memory error
");
        return NULL;
    }

    graph->numVertices = vertices;

    // Create an array to store the adjacency lists
    graph->adjLists = (AdjListNode**) malloc(vertices * sizeof(AdjListNode*));
    for (int i = 0; i < vertices; i++) {
        graph->adjLists[i] = NULL;
    }

    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int src, int dest) {
    // Add an edge from src to dest
    AdjListNode* newNode = createNode(dest);
    newNode->next = graph->adjLists[src];
    graph->adjLists[src] = newNode;

    // Add an edge from dest to src
    newNode = createNode(src);
    newNode->next = graph->adjLists[dest];
    graph->adjLists[dest] = newNode;
}

// Function to perform DFS
int dfs(int vertex, int color[], Graph* graph, int col) {
    color[vertex] = col;

    AdjListNode* temp = graph->adjLists[vertex];

    while (temp) {
        if (color[temp->vertex] == -1) {
            if (!dfs(temp->vertex, color, graph, 1 - col)) {
                return 0;
            }
        } else if (color[temp->vertex] == col) {
            return 0;
        }
        temp = temp->next;
    }
    return 1;
}

// Function to check if the graph is bipartite
int isBipartite(Graph* graph) {
    int* color = (int*) malloc(sizeof(int) * graph->numVertices);
    for (int i = 0; i < graph->numVertices; i++) {
        color[i] = -1;
    }

    for (int i = 0; i < graph->numVertices; i++) {
        if (color[i] == -1) {
            if (!dfs(i, color, graph, 0)) {
                free(color);
                return 0;
            }
        }
    }

    free(color);
    return 1;
}

int main() {
    int vertices;
    printf("Enter the number of vertices: ");
    scanf("%d", &vertices);

    Graph* graph = createGraph(vertices);

    printf("Enter the edges (src dest): ");
    for (int i = 0; i < vertices; i++) {
        int src, dest;
        scanf("%d %d", &src, &dest);
        addEdge(graph, src, dest);
    }

    if (isBipartite(graph)) {
        printf("The graph is bipartite.
");
    } else {
        printf("The graph is not bipartite.
");
    }

    return 0;
}

